for group, count in top_groups:
    print(f"{group}: {count} patents")

print("__RESULT__:")
print(json.dumps({
    'total_groups': len(cpc_groups_2019),
    'top_groups': top_groups[:10],
    'cpc_details': cpc_details
}))"}

