{"code": "import json
import re

# Load German patents data
result_file = var_functions.query_db:40
with open(result_file, 'r') as f:
    all_patents = json.load(f)

print("Loaded {} German patents".format(len(all_patents)))

# Filter for H2 2019 patents
h2_2019_patents = []
for patent in all_patents:
    grant_date = patent.get('grant_date', '').lower()
    # Check for 2019 and second half months
    if '2019' in grant_date and any(month in grant_date for month in ['jul','aug','sep','oct','nov','dec']):
        h2_2019_patents.append(patent)

print("Found {} patents granted in H2 2019".format(len(h2_2019_patents)))

# Extract CPC level 4 groups
cpc_groups_count = {}
for patent in h2_2019_patents:
    try:
        cpc_list = json.loads(patent['cpc'])
        for entry in cpc_list:
            code = entry.get('code', '')
            # Extract level 4 group (before /)
            if '/' in code:
                group = code.split('/')[0]
                # Validate format (4 characters then digits)
                if re.match(r'^[A-Z]\d{2}[A-Z]\d{2}$', group):
                    cpc_groups_count[group] = cpc_groups_count.get(group, 0) + 1
    except:
        continue

print("Unique level 4 CPC groups in H2 2019: {}".format(len(cpc_groups_count)))
top_groups = sorted(cpc_groups_count.items(), key=lambda x: x[1], reverse=True)[:10]
print("Top 10 groups:", top_groups)

# For EMA calculation, we need historical patent counts by year for these groups
# Let's collect patent counts by year for all German patents
yearly_counts = {}
year_pattern = re.compile(r'(\d{4})')

def extract_group(code):
    if '/' in code:
        group = code.split('/')[0]
        if re.match(r'^[A-Z]\d{2}[A-Z]\d{2}$', group):
            return group
    return None

# Collect all relevant CPC groups (at least those in H2 2019)
all_groups = set(cpc_groups_count.keys())

# Build yearly patent counts for each group
for patent in all_patents:
    grant_date = patent.get('grant_date', '')
    year_match = year_pattern.search(grant_date)
    if year_match:
        year = int(year_match.group(1))
        if year not in yearly_counts:
            yearly_counts[year] = {}

        try:
            cpc_list = json.loads(patent['cpc'])
            for entry in cpc_list:
                code = entry.get('code', '')
                group = extract_group(code)
                if group and group in all_groups:
                    yearly_counts[year][group] = yearly_counts[year].get(group, 0) + 1
        except:
            continue

# Calculate EMA for each group
alpha = 0.1
results = []

for group in all_groups:
    years = sorted(yearly_counts.keys())
    ema_prev = 0
    max_ema = 0
    best_year = None

    for year in years:
        count = yearly_counts[year].get(group, 0)
        ema = alpha * count + (1 - alpha) * ema_prev

        if ema > max_ema:
            max_ema = ema
            best_year = year

        ema_prev = ema

    # Only include groups present in H2 2019
    if cpc_groups_count.get(group, 0) > 0:
        results.append({
            'cpc_group_code': group,
            'max_ema': max_ema,
            'best_year': best_year,
            'h2_2019_count': cpc_groups_count[group]
        })

# Sort by max EMA
top_results = sorted(results, key=lambda x: x['max_ema'], reverse=True)[:10]
print("Top groups by EMA: {}".format(top_results))

print("__RESULT__:")
print(json.dumps({
    'h2_2019_patents': len(h2_2019_patents),
    'unique_cpc_groups': len(cpc_groups_count),
    'top_ema_groups': top_results
}))
"}

{"code": "import json, re
from collections import defaultdict

# Access the results using proper variable names
file_key = 'var_functions.query_db:40'
result_file_path = globals()[file_key]

with open(result_file_path, 'r') as f:
    all_patents = json.load(f)

print("Loaded {} patents".format(len(all_patents)))

# First, let's just identify all relevant CPC groups and their yearly counts
yearly_group_counts = defaultdict(lambda: defaultdict(int))
year_pattern = re.compile(r'(\d{4})')

code_pattern = re.compile(r'^[A-Z]\d{2}[A-Z]\d{2}$')

for p in all_patents:
    date = p.get('grant_date', '')
    m = year_pattern.search(date)
    if m:
        year = int(m.group(1))
        try:
            cpc_list = json.loads(p['cpc'])
            for entry in cpc_list:
                code = entry.get('code', '')
                if '/' in code:
                    group = code.split('/')[0]
                    if code_pattern.match(group):
                        yearly_group_counts[year][group] += 1
        except:
            pass

# Filter for H2 2019
h2_2019_groups = defaultdict(int)
for p in all_patents:
    date = p.get('grant_date', '').lower()
    if '2019' in date and any(m in date for m in ['jul','aug','sep','oct','nov','dec']):
        try:
            cpc_list = json.loads(p['cpc'])
            for entry in cpc_list:
                code = entry.get('code', '')
                if '/' in code:
                    group = code.split('/')[0]
                    if code_pattern.match(group):
                        h2_2019_groups[group] += 1
        except:
            pass

print("H2 2019 groups count: {}".format(len(h2_2019_groups)))
print("Year range: {} to {}".format(min(yearly_group_counts.keys()), max(yearly_group_counts.keys())))

# Calculate EMA for groups in H2 2019
alpha = 0.1
results = []

candidates = list(h2_2019_groups.items())
for group, count_2019 in candidates:
    if count_2019 == 0:
        continue

    years = sorted(yearly_group_counts.keys())
    ema_prev = 0
    max_ema = 0
    best_year = None

    for year in years:
        count = yearly_group_counts[year].get(group, 0)
        ema = alpha * count + (1 - alpha) * ema_prev

        if ema > max_ema:
            max_ema = ema
            best_year = year

        ema_prev = ema

    results.append({
        'cpc_group_code': group,
        'best_year': best_year,
        'max_ema': max_ema,
        'h2_2019_count': count_2019
    })

top_results = sorted(results, key=lambda x: x['max_ema'], reverse=True)[:10]
print("Top by EMA: {}".format(top_results))

print("__RESULT__:")
print(json.dumps({
    'h2_2019_groups': len(h2_2019_groups),
    'top_ema_groups': top_results
}))
"}

